export const colorCategories: ColorCategory[] = ['Red', 'Pink', 'Purple', 'Blue', 'Cyan', 'Teal', 'Green', 'Lime', 'Yellow', 'Orange', 'Brown', 'White', 'Gray', 'Black'];

export function getColorBySlug(slug: string): ColorData | undefined {
  return colors.find(c => c.slug === slug);
}

export function getColorsByCategory(category: ColorCategory): ColorData[] {
  return colors.filter(c => c.category === category);
}

export function getRelatedColors(color: ColorData): ColorData[] {
  return color.related.map(slug => getColorBySlug(slug)).filter(Boolean) as ColorData[];
}

export function hexToRgbData(hex: string): { r: number; g: number; b: number } | null {
  const h = hex.replace('#', '');
  if (h.length !== 6 && h.length !== 3) return null;
  const full = h.length === 3 ? h.split('').map(c => c + c).join('') : h;
  if (!/^[0-9a-fA-F]+$/.test(full)) return null;
  return {
    r: parseInt(full.substring(0, 2), 16),
    g: parseInt(full.substring(2, 4), 16),
    b: parseInt(full.substring(4, 6), 16),
  };
}
